      c6: document.querySelector('.sheet-cell[data-address="C6"] .cell-content')?.textContent || "",
      c6Formula: sheet?.cells?.["6:3"]?.formula || "",
      calculatedFormula: table?.columns?.[2]?.calculatedColumnFormula || "",
